# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

def update_account_balances(transactions):
    accounts = {}
    
    for transaction in transactions:
        account, amount = transaction
        if account not in accounts:
            accounts[account] = 0.0
        accounts[account] += amount
    
    return accounts

# Example usage:
transactions = [
    ("Alice", 100.0),
    ("Bob", -50.0),
    ("Alice", 200.0),
    ("Charlie", 300.0),
    ("Bob", 150.0)
]

balances = update_account_balances(transactions)
print(balances)